import type { Metadata } from "next";

import BusOperations from "./BusOperations";

export const metadata: Metadata = {
  title: "運行管理（路線バス） — 渋66 渋谷駅前〜等々力 | ぐんじょう バス",
  description:
    "路線バスの運行管理者（営業所）向け運行管理コンソール。系統 渋66（渋谷駅前〜等々力）の在線状況を一覧（便・号車・運転士・現在地・遅延/早発・次停留所・状態）で監視し、続行（だんご運転）・大幅遅延・早発・乗務員交代などの要対応を重大度順にトリアージ。運行図表（時間×距離のスジ／計画ダイヤvs実績）で遅延波及・続行を読み取り、車両・乗務員の運用（出庫→便→折返し→入庫）をガントで確認、増発・運休・続行解消・迂回などの運転整理を署名・2人確認つきで記録する管制画面。",
};

export default function BusOperationsPage() {
  return <BusOperations />;
}

"use client";

import * as React from "react";
import type { ColumnDef } from "@tanstack/react-table";
import {
  ActionDataTable,
  ActionQueue,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  CoSign,
  type CoSignValue,
  Delta,
  Gantt,
  type GanttItem,
  type GanttRow,
  RouteStops,
  type RouteStopItem,
  SignedRecord,
  type SignedRecordValue,
  StatGroup,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  Textarea,
  ThemeProvider,
} from "@gunjo/ui";

import { RunDiagram } from "./RunDiagram";
import {
  ACTIONS,
  CONTROL_LOG,
  DEPOT,
  type LiveRun,
  LIVE_RUNS,
  NOW_HM,
  OPERATING_DAY,
  ROUTE_LABEL,
  ROUTE_NAME,
  RUNS,
  STOPS,
  WORKINGS,
} from "./data";

const SIGNER_ID = "kanno";

// ---- Live runs table (在線状況) ---------------------------------------------

const stateBadge: Record<LiveRun["state"], { variant: "secondary" | "info" | "success" | "destructive" | "warning"; }> = {
  運行中: { variant: "success" },
  遅延: { variant: "destructive" },
  早発: { variant: "warning" },
  続行: { variant: "destructive" },
  回送: { variant: "secondary" },
};

const liveColumns: ColumnDef<LiveRun>[] = [
  {
    accessorKey: "trip",
    header: "便",
    cell: ({ row }) => (
      <span className="font-medium tabular-nums">{row.original.trip}</span>
    ),
  },
  {
    accessorKey: "direction",
    header: "方向",
    cell: ({ row }) => (row.original.direction === "down" ? "下り" : "上り"),
  },
  { accessorKey: "car", header: "号車" },
  { accessorKey: "driver", header: "運転士" },
  { accessorKey: "near", header: "現在地" },
  { accessorKey: "nextStop", header: "次停留所" },
  {
    accessorKey: "delayMin",
    header: "遅延/早発",
    cell: ({ row }) => (
      <Delta
        value={row.original.delayMin}
        format={(v) =>
          v === 0 ? "定時" : `${v > 0 ? "+" : "−"}${Math.abs(v)}分`
        }
        labels={{ positive: "遅延", negative: "早発", zero: "定時" }}
        tones={{ positive: "destructive", negative: "warning", zero: "success" }}
        showLabel
      />
    ),
  },
  {
    accessorKey: "state",
    header: "状態",
    cell: ({ row }) => {
      const s = row.original.state;
      return <Badge variant={stateBadge[s].variant}>{s}</Badge>;
    },
  },
];

// ---- Workings Gantt (車両・乗務員 運用) --------------------------------------

const ganttRows: GanttRow[] = WORKINGS.map((w) => ({
  id: w.carId,
  label: w.carLabel,
  sublabel: `${w.duty}・${w.driver}`,
}));

const ganttItems: GanttItem[] = WORKINGS.map((w) => {
  const start = w.segments[0].start;
  const end = w.segments[w.segments.length - 1].end;
  return {
    id: w.carId,
    rowId: w.carId,
    start,
    end,
    label: `${w.duty} 行路`,
    ariaLabel: `${w.carLabel} ${w.duty} ${w.driver} の運用`,
    segments: w.segments.map((s) => ({
      start: s.start,
      end: s.end,
      kind: s.kind,
      label: s.label,
      tone: s.tone,
    })),
  };
});

// Hour ticks for the page-local scale strip above the Gantt (the kit's Gantt
// header is day-column resolution, so intraday hours need a local ruler).
const WORK_START_MIN = 8 * 60 + 45;
const WORK_END_MIN = 11 * 60 + 30;

function hourScale() {
  const out: { label: string; pct: number }[] = [];
  for (let m = 9 * 60; m <= WORK_END_MIN; m += 30) {
    out.push({
      label: `${Math.floor(m / 60)}:${String(m % 60).padStart(2, "0")}`,
      pct: ((m - WORK_START_MIN) / (WORK_END_MIN - WORK_START_MIN)) * 100,
    });
  }
  return out;
}

// ---- Component --------------------------------------------------------------

export default function BusOperations() {
  const [focusedRun, setFocusedRun] = React.useState<string>("r07");
  const [log, setLog] = React.useState<SignedRecordValue>({
    status: "draft",
    addenda: [],
  });
  const [cosign, setCosign] = React.useState<CoSignValue | undefined>(undefined);
  const [decision, setDecision] = React.useState("");

  const focused = RUNS.find((r) => r.id === focusedRun);
  const focusedLive = LIVE_RUNS.find((r) => r.id === focusedRun);

  // Drilldown: focused run as a stop-by-stop progress list.
  const drilldownStops: RouteStopItem[] = focused
    ? focused.points.map((p, i) => {
        const stop = STOPS.find((s) => s.id === p.stopId)!;
        const done = !!p.actual;
        const isCurrent =
          done && i + 1 < focused.points.length && !focused.points[i + 1].actual;
        const status: RouteStopItem["status"] = isCurrent
          ? "current"
          : done
          ? "completed"
          : "pending";
        return {
          id: p.stopId,
          seq: i + 1,
          title: stop.name,
          status,
          plannedTime: p.planned,
          actualTime: p.actual,
        };
      })
    : [];

  const kpis = [
    { label: "運行中", value: "5", hint: "渋66 系統" },
    {
      label: "遅延便",
      value: "2",
      change: "+1",
      trend: "up" as const,
      tone: "negative" as const,
      hint: "前30分比",
    },
    { label: "定時運行率", value: "78%", change: "−6pt", trend: "down" as const, tone: "negative" as const, hint: "目標 90%" },
    { label: "要対応", value: "3", hint: "重大1・警告2" },
  ];

  return (
    <ThemeProvider defaultTheme="light">
      <div className="mx-auto flex min-h-screen w-full max-w-[1280px] flex-col gap-4 p-4 md:p-6">
        {/* Header — built from primitives (no desktop ops app-bar component fit). */}
        <header className="flex flex-wrap items-end justify-between gap-3 border-b border-border pb-4">
          <div>
            <div className="flex items-center gap-2">
              <h1 className="text-xl font-bold tracking-tight">運行管理</h1>
              <Badge variant="info">{ROUTE_LABEL}</Badge>
              <span className="text-sm text-muted-foreground">{ROUTE_NAME}</span>
            </div>
            <p className="mt-1 text-sm text-muted-foreground">
              {DEPOT}・運行管理者 菅野 · {OPERATING_DAY}（現在 {NOW_HM}）
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm">
              ダイヤ表示
            </Button>
            <Button variant="outline" size="sm">
              無線
            </Button>
            <Button variant="primary" size="sm">
              指令を発令
            </Button>
          </div>
        </header>

        {/* KPI strip */}
        <StatGroup items={kpis} cols={{ base: 2, md: 4 }} />

        {/* Top row: run diagram + action queue */}
        <div className="grid grid-cols-1 gap-4 xl:grid-cols-[1fr_360px]">
          <Card>
            <CardHeader>
              <CardTitle className="text-base">運行図表（時間 × 距離）</CardTitle>
              <CardDescription>
                斜線が各便。点線＝計画ダイヤ、実線＝実績。下り（青）／上り（緑）。便をクリックで右の在線・停留所進行と連動。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <RunDiagram
                stops={STOPS}
                runs={RUNS}
                windowStart="09:00"
                windowEnd="10:30"
                now={NOW_HM}
                focusedId={focusedRun}
                onFocusRun={setFocusedRun}
              />
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="text-base">要対応</CardTitle>
              <CardDescription>重大度順。続行・遅延・早発・乗務交代。</CardDescription>
            </CardHeader>
            <CardContent>
              <ActionQueue
                items={ACTIONS.map((a) => ({
                  id: a.id,
                  severity: a.severity,
                  kind: a.kind,
                  title: a.title,
                  detail: a.detail,
                  meta: a.meta,
                  actions: (
                    <Button variant="outline" size="sm">
                      対応
                    </Button>
                  ),
                }))}
              />
            </CardContent>
          </Card>
        </div>

        {/* Tabs: 在線状況 / 運用 / 便詳細 */}
        <Tabs defaultValue="live" className="w-full">
          <TabsList>
            <TabsTrigger value="live">在線状況</TabsTrigger>
            <TabsTrigger value="workings">車両・乗務員運用</TabsTrigger>
            <TabsTrigger value="detail">便詳細</TabsTrigger>
          </TabsList>

          <TabsContent value="live">
            <ActionDataTable
              columns={liveColumns}
              data={LIVE_RUNS}
              getRowId={(r) => r.id}
              getRowLabel={(r) => r.trip}
              onRowClick={(r) => setFocusedRun(r.id)}
              rowActions={[
                {
                  id: "focus",
                  label: "図表で表示",
                  onSelect: (r) => setFocusedRun(r.id),
                },
                {
                  id: "radio",
                  label: "無線呼出",
                  onSelect: () => {},
                },
              ]}
              filter={{ columnId: "trip", placeholder: "便で絞り込み" }}
            />
          </TabsContent>

          <TabsContent value="workings">
            <div className="flex flex-col gap-1">
              {/* page-local hour ruler — Gantt's own header is day-resolution */}
              <div className="relative ml-[120px] h-4 text-[10px] text-muted-foreground">
                {hourScale().map((t) => (
                  <span
                    key={t.label}
                    className="absolute -translate-x-1/2 tabular-nums"
                    style={{ left: `${t.pct}%` }}
                  >
                    {t.label}
                  </span>
                ))}
              </div>
              <Gantt
                rows={ganttRows}
                items={ganttItems}
                startDate={`${OPERATING_DAY}T08:45`}
                endDate={`${OPERATING_DAY}T11:30`}
                today={`${OPERATING_DAY}T${NOW_HM}`}
                rowLabelWidth={120}
                dayWidth={760}
                laneHeight={26}
                label="車両・乗務員の運用（出庫→便→折返し→入庫）"
                onSelectItem={(it) => setFocusedRun(it.id)}
              />
              <p className="mt-1 text-xs text-muted-foreground">
                各バー＝1運用。色分け：出庫/回送/休憩＝灰、便＝青、折返し＝水。縦線＝現在時刻。
              </p>
            </div>
          </TabsContent>

          <TabsContent value="detail">
            {focused ? (
              <div className="grid grid-cols-1 gap-4 lg:grid-cols-[280px_1fr]">
                <div className="flex flex-col gap-2">
                  <h3 className="text-sm font-semibold">
                    {focused.trip}（{focused.direction === "down" ? "下り" : "上り"}）
                  </h3>
                  <dl className="grid grid-cols-[auto_1fr] gap-x-4 gap-y-1 text-sm">
                    <dt className="text-muted-foreground">号車</dt>
                    <dd>{focused.car}</dd>
                    <dt className="text-muted-foreground">運転士</dt>
                    <dd>{focused.driver}</dd>
                    <dt className="text-muted-foreground">仕業</dt>
                    <dd>{focused.duty}</dd>
                    <dt className="text-muted-foreground">状態</dt>
                    <dd>
                      {focusedLive ? (
                        <Delta
                          value={focusedLive.delayMin}
                          format={(v) =>
                            v === 0 ? "定時" : `${v > 0 ? "+" : "−"}${Math.abs(v)}分`
                          }
                          labels={{ positive: "遅延", negative: "早発", zero: "定時" }}
                          tones={{ positive: "destructive", negative: "warning", zero: "success" }}
                          showLabel
                        />
                      ) : (
                        "—"
                      )}
                    </dd>
                  </dl>
                </div>
                <RouteStops
                  stops={drilldownStops}
                  timeLabels={{ planned: "ダイヤ", actual: "実績" }}
                />
              </div>
            ) : null}
          </TabsContent>
        </Tabs>

        {/* Control log — signed/audited 指令記録 */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base">指令記録（運転整理）</CardTitle>
            <CardDescription>
              増発・運休・続行解消・迂回などの管制判断。確定（署名）すると追記のみ。重大判断は2人確認。
            </CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4">
            {/* existing log */}
            <ul className="flex flex-col gap-2">
              {CONTROL_LOG.map((e) => (
                <li
                  key={e.id}
                  className="flex flex-col gap-1 rounded-md border border-border bg-card p-3 text-sm"
                >
                  <div className="flex items-center gap-2">
                    <Badge variant="outline">{e.action}</Badge>
                    <span className="tabular-nums text-xs text-muted-foreground">
                      {e.at.replace("T", " ")} · {e.author}
                    </span>
                  </div>
                  <p>{e.body}</p>
                </li>
              ))}
            </ul>

            <SignedRecord
              value={log}
              onChange={setLog}
              signerId={SIGNER_ID}
              canSign={decision.trim().length > 0}
            >
              {({ readOnly }) => (
                <div className="flex flex-col gap-2">
                  <label className="text-sm font-medium" htmlFor="decision">
                    新規指令（運転整理）
                  </label>
                  <Textarea
                    id="decision"
                    value={decision}
                    onChange={(e) => setDecision(e.target.value)}
                    disabled={readOnly}
                    placeholder="例）渋66-09 を松濤で2分時間調整し、-07 との続行を解消。次便 -11 はそのまま。"
                    rows={3}
                  />
                </div>
              )}
            </SignedRecord>

            {/* 2人確認 for the signed decision */}
            <div className="rounded-md border border-border p-3">
              <p className="mb-2 text-sm font-medium">運休・区間運休の2人確認</p>
              <CoSign
                primaryId={SIGNER_ID}
                value={cosign}
                onSign={setCosign}
                requireReason
                attestations={[
                  { id: "att-route", label: "対象系統・区間を確認した" },
                  { id: "att-notice", label: "営業所・運転士へ周知済み" },
                ]}
                signerLabel="確認者ID（当務助役）"
              />
            </div>
          </CardContent>
        </Card>
      </div>
    </ThemeProvider>
  );
}

// 路線バス 運行管理 — sample domain data.
// 営業所: 東京都交通局 江東自動車営業所 風  / 系統 渋66（渋谷駅前〜等々力）down/up。
// All times are "today" (the operating day) in HH:MM. NOW = 09:42.

export const NOW_HM = "09:42";
export const OPERATING_DAY = "2026-06-28";
export const DEPOT = "江東自動車営業所";
export const ROUTE_LABEL = "渋66";
export const ROUTE_NAME = "渋谷駅前 〜 等々力";

/** Bus stops down the line (距離軸). Index 0 = 始発, last = 終点. `km` = cumulative route distance. */
export interface Stop {
  id: string;
  name: string;
  km: number;
}

export const STOPS: Stop[] = [
  { id: "s0", name: "渋谷駅前", km: 0.0 },
  { id: "s1", name: "神泉町", km: 0.9 },
  { id: "s2", name: "神山町", km: 1.6 },
  { id: "s3", name: "松濤", km: 2.3 },
  { id: "s4", name: "東大裏", km: 3.1 },
  { id: "s5", name: "駒場", km: 4.0 },
  { id: "s6", name: "三宿", km: 5.2 },
  { id: "s7", name: "野沢龍雲寺", km: 6.4 },
  { id: "s8", name: "深沢不動前", km: 7.9 },
  { id: "s9", name: "等々力", km: 9.3 },
];

export type RunDirection = "down" | "up"; // down = 渋谷→等々力, up = 等々力→渋谷

/** One scheduled timing point on a run: planned arrival, and (where known) actual. */
export interface RunPoint {
  stopId: string;
  planned: string; // HH:MM
  actual?: string; // HH:MM — set up to current position
}

export interface BusRun {
  id: string;
  /** 便（ダイヤ上の便号）. */
  trip: string;
  direction: RunDirection;
  /** ○○号車. */
  car: string;
  /** 運転士（乗務員）. */
  driver: string;
  /** 仕業（交番）番号. */
  duty: string;
  points: RunPoint[];
}

// Helper to build runs concisely.
function pts(
  stops: string[],
  planned: string[],
  actual: (string | undefined)[] = []
): RunPoint[] {
  return stops.map((stopId, i) => ({
    stopId,
    planned: planned[i],
    actual: actual[i],
  }));
}

const DOWN = STOPS.map((s) => s.id); // s0..s9
const UP = [...DOWN].reverse(); // s9..s0

// A handful of runs that overlap "now" so the diagram and live list are populated.
export const RUNS: BusRun[] = [
  // 渋66-07: down, departed 09:10, on time-ish, currently near 駒場
  {
    id: "r07",
    trip: "渋66-07",
    direction: "down",
    car: "C-1182",
    driver: "佐久間 亮",
    duty: "甲3",
    points: pts(
      DOWN,
      ["09:10", "09:14", "09:17", "09:21", "09:26", "09:31", "09:38", "09:45", "09:52", "10:00"],
      ["09:10", "09:15", "09:18", "09:22", "09:28", "09:33", undefined, undefined, undefined, undefined]
    ),
  },
  // 渋66-09: down, departed 09:22, badly delayed (続行/だんご運転 with -07), near 松濤
  {
    id: "r09",
    trip: "渋66-09",
    direction: "down",
    car: "C-1207",
    driver: "西脇 真",
    duty: "甲5",
    points: pts(
      DOWN,
      ["09:22", "09:26", "09:29", "09:33", "09:38", "09:43", "09:50", "09:57", "10:04", "10:12"],
      ["09:26", "09:33", "09:38", "09:44", undefined, undefined, undefined, undefined, undefined, undefined]
    ),
  },
  // 渋66-11: down, departed 09:40, just left, on time
  {
    id: "r11",
    trip: "渋66-11",
    direction: "down",
    car: "C-1190",
    driver: "高梨 由貴",
    duty: "甲7",
    points: pts(
      DOWN,
      ["09:40", "09:44", "09:47", "09:51", "09:56", "10:01", "10:08", "10:15", "10:22", "10:30"],
      ["09:41", "09:45", undefined, undefined, undefined, undefined, undefined, undefined, undefined, undefined]
    ),
  },
  // 渋66-12: up, departed 等々力 09:05, near 三宿, early (早発気味)
  {
    id: "r12",
    trip: "渋66-12",
    direction: "up",
    car: "C-1175",
    driver: "大津 健",
    duty: "乙2",
    points: pts(
      UP,
      ["09:05", "09:12", "09:18", "09:24", "09:30", "09:36", "09:41", "09:45", "09:48", "09:52"],
      ["09:05", "09:11", "09:16", "09:21", "09:27", undefined, undefined, undefined, undefined, undefined]
    ),
  },
  // 渋66-14: up, departed 等々力 09:25, on time, near 深沢不動前
  {
    id: "r14",
    trip: "渋66-14",
    direction: "up",
    car: "C-1213",
    driver: "森下 香織",
    duty: "乙4",
    points: pts(
      UP,
      ["09:25", "09:33", "09:39", "09:45", "09:51", "09:57", "10:03", "10:08", "10:12", "10:17"],
      ["09:25", "09:34", undefined, undefined, undefined, undefined, undefined, undefined, undefined, undefined]
    ),
  },
];

/** Live-runs table row (在線状況). Derived-ish but written out for clarity. */
export interface LiveRun {
  id: string;
  trip: string;
  direction: RunDirection;
  car: string;
  driver: string;
  near: string; // 現在地（バス停付近）
  nextStop: string;
  delayMin: number; // +遅延 / −早発
  state: "運行中" | "遅延" | "早発" | "続行" | "回送";
}

export const LIVE_RUNS: LiveRun[] = [
  { id: "r07", trip: "渋66-07", direction: "down", car: "C-1182", driver: "佐久間 亮", near: "駒場", nextStop: "三宿", delayMin: 2, state: "運行中" },
  { id: "r09", trip: "渋66-09", direction: "down", car: "C-1207", driver: "西脇 真", near: "松濤", nextStop: "東大裏", delayMin: 6, state: "続行" },
