"use client";

// 運行図表 / ダイヤグラム (time–distance "stringline" / Marey diagram).
//
// HAND-ROLLED. @gunjo/ui has NO primitive for this — the docs explicitly say
// "交差する斜線(列車運行図表/ダイヤグラム/Marey) は未対応". Gantt is horizontal
// bars on resource rows (a bus = one row); a run diagram is the orthogonal view:
// the Y axis is DISTANCE (the line's stops), the X axis is TIME, and each run is
// a DIAGONAL polyline whose slope is speed and whose kinks are dwells. A bus
// appears as a line crossing every stop, and two buses bunching shows as two
// lines drawing close together — which no row-bar chart can express.
//
// SVG is appropriate here per the repo guidance: this is data-driven, but the
// shape (axes + polylines) is a fixed geometric form, and lines/markers are the
// natural primitive. Planned = dashed, actual = solid; a vertical now-line marks
// current time.

import * as React from "react";
import type { BusRun, Stop } from "./data";

interface RunDiagramProps {
  stops: Stop[];
  runs: BusRun[];
  /** Window start "HH:MM". */
  windowStart: string;
  /** Window end "HH:MM". */
  windowEnd: string;
  /** Current time "HH:MM" for the now-line. */
  now: string;
  /** Currently focused run id (highlighted). */
  focusedId?: string;
  onFocusRun?: (id: string) => void;
}

const PAD = { top: 24, right: 20, bottom: 28, left: 96 };
const PLOT_W = 760;
const ROW_H = 34;

function hmToMin(hm: string): number {
  const [h, m] = hm.split(":").map(Number);
  return h * 60 + m;
}

export function RunDiagram({
  stops,
  runs,
  windowStart,
  windowEnd,
  now,
  focusedId,
  onFocusRun,
}: RunDiagramProps) {
  const t0 = hmToMin(windowStart);
  const t1 = hmToMin(windowEnd);
  const span = Math.max(1, t1 - t0);

  const plotH = (stops.length - 1) * ROW_H;
  const W = PAD.left + PLOT_W + PAD.right;
  const H = PAD.top + plotH + PAD.bottom;

  const x = (min: number) => PAD.left + ((min - t0) / span) * PLOT_W;
  const stopY = (idx: number) => PAD.top + idx * ROW_H;
  const yByStop = React.useMemo(() => {
    const map = new Map<string, number>();
    stops.forEach((s, i) => map.set(s.id, stopY(i)));
    return map;
  }, [stops]);

  // Hour gridlines.
  const hourTicks: number[] = [];
  for (let m = Math.ceil(t0 / 30) * 30; m <= t1; m += 30) hourTicks.push(m);

  const nowX = x(hmToMin(now));

  function polyPoints(run: BusRun, key: "planned" | "actual"): string {
    const pts: string[] = [];
    for (const p of run.points) {
      const t = key === "actual" ? p.actual : p.planned;
      if (!t) continue;
      const y = yByStop.get(p.stopId);
      if (y == null) continue;
      pts.push(`${x(hmToMin(t)).toFixed(1)},${y.toFixed(1)}`);
    }
    return pts.join(" ");
  }

  // Down runs lean one hue, up runs another — direction is legible at a glance.
  const colorFor = (run: BusRun, focused: boolean) => {
    if (focused) return "var(--primary, #2563eb)";
    return run.direction === "down" ? "#1d4ed8" : "#0f766e";
  };

  return (
    <figure className="m-0 w-full overflow-x-auto">
      <figcaption className="sr-only">
        運行図表（時間×距離）。縦軸は {stops[0].name} から {stops[stops.length - 1].name} までの停留所、
        横軸は時刻。各斜線が1便の運行で、点線が計画ダイヤ、実線が実績。垂直線が現在時刻 {now}。
      </figcaption>
      <svg
        role="img"
        aria-label={`渋66 運行図表 ${windowStart}〜${windowEnd}、現在 ${now}`}
        viewBox={`0 0 ${W} ${H}`}
        width={W}
        height={H}
        className="min-w-[760px] text-foreground"
      >
        {/* hour gridlines + time labels */}
        {hourTicks.map((m) => {
          const tx = x(m);
          const hh = Math.floor(m / 60);
          const mm = m % 60;
          return (
            <g key={`t-${m}`}>
              <line
                x1={tx}
                y1={PAD.top}
                x2={tx}
                y2={PAD.top + plotH}
                stroke="var(--border, #e5e7eb)"
                strokeWidth={1}
              />
              <text
                x={tx}
                y={PAD.top + plotH + 18}
                textAnchor="middle"
                className="fill-muted-foreground"
                fontSize={10}
              >
                {`${hh}:${String(mm).padStart(2, "0")}`}
              </text>
            </g>
          );
        })}

        {/* stop rows + labels (距離軸) */}
        {stops.map((s, i) => {
          const y = stopY(i);
          return (
            <g key={s.id}>
              <line
                x1={PAD.left}
                y1={y}
                x2={PAD.left + PLOT_W}
                y2={y}
                stroke="var(--border, #e5e7eb)"
                strokeWidth={1}
              />
              <text
                x={PAD.left - 8}
                y={y + 3}
                textAnchor="end"
                className="fill-foreground"
                fontSize={11}
              >
                {s.name}
              </text>
            </g>
          );
        })}

        {/* now-line */}
        {nowX >= PAD.left && nowX <= PAD.left + PLOT_W && (
          <g>
            <line
              x1={nowX}
              y1={PAD.top - 6}
              x2={nowX}
              y2={PAD.top + plotH}
              stroke="var(--destructive, #dc2626)"
              strokeWidth={1.5}
            />
            <text
              x={nowX}
              y={PAD.top - 10}
              textAnchor="middle"
              className="fill-destructive"
              fontSize={10}
              fontWeight={600}
            >
              現在 {now}
            </text>
          </g>
        )}

        {/* run lines: planned (dashed) + actual (solid) */}
        {runs.map((run) => {
          const focused = run.id === focusedId;
          const stroke = colorFor(run, focused);
          const planned = polyPoints(run, "planned");
          const actual = polyPoints(run, "actual");
          // Place the trip label at the first planned point.
          const first = run.points.find((p) => p.planned);
          const labelX = first ? x(hmToMin(first.planned)) : PAD.left;
          const labelY = first ? (yByStop.get(first.stopId) ?? PAD.top) : PAD.top;
          return (
            <g
              key={run.id}
              role="button"
              tabIndex={0}
              aria-label={`${run.trip}、${run.direction === "down" ? "下り" : "上り"}、${run.car}、運転士 ${run.driver}`}
              aria-pressed={focused}
              onClick={() => onFocusRun?.(run.id)}
              onKeyDown={(e) => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault();
                  onFocusRun?.(run.id);
                }
              }}
              className="cursor-pointer outline-none [&:focus-visible_polyline]:opacity-100"
            >
              {planned && (
                <polyline
                  points={planned}
                  fill="none"
                  stroke={stroke}
                  strokeWidth={focused ? 1.5 : 1}
                  strokeDasharray="3 3"
                  opacity={focused ? 0.9 : 0.45}
                />
              )}
              {actual && (
                <polyline
                  points={actual}
                  fill="none"
                  stroke={stroke}
                  strokeWidth={focused ? 3 : 2}
                  strokeLinejoin="round"
                  strokeLinecap="round"
                  opacity={focused ? 1 : 0.85}
                />
              )}
              {/* actual-position dot at the leading edge */}
              {actual &&
                (() => {
                  const lastActual = [...run.points]
                    .reverse()
                    .find((p) => p.actual);
                  if (!lastActual?.actual) return null;
                  const cx = x(hmToMin(lastActual.actual));
                  const cy = yByStop.get(lastActual.stopId) ?? 0;
                  return <circle cx={cx} cy={cy} r={focused ? 4 : 3} fill={stroke} />;
                })()}
              <text
                x={labelX}
                y={labelY - 5}
                className="fill-foreground"
                fontSize={9}
                fontWeight={focused ? 700 : 400}
              >
                {run.trip}
              </text>
            </g>
          );
        })}
      </svg>
    </figure>
  );
}
